import{_ as e,o as n,c as o,a2 as i}from"./chunks/framework.4hJCcvDE.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_005-3D数学基础.md","filePath":"blog/知识点_005-3D数学基础.md","lastUpdated":1784835052000}'),t={name:"blog/知识点_005-3D数学基础.md"};function s(r,a,l,d,p,c){return n(),o("div",null,[...a[0]||(a[0]=[i(`<h2 id="四、四元数-quaternion" tabindex="-1">四、四元数（Quaternion） <a class="header-anchor" href="#四、四元数-quaternion" aria-label="Permalink to &quot;四、四元数（Quaternion）&quot;">​</a></h2><h3 id="_1-为什么需要四元数" tabindex="-1">1. 为什么需要四元数 <a class="header-anchor" href="#_1-为什么需要四元数" aria-label="Permalink to &quot;1. 为什么需要四元数&quot;">​</a></h3><p>旋转矩阵可以做任意旋转，但在做插值和组合时有两个致命问题：</p><ul><li><strong>万向节死锁（Gimbal Lock）</strong>：用欧拉角（绕 X/Y/Z 轴依次旋转）时，中间轴的 90° 旋转会使得另外两个轴的旋转方向重合，丢失一个自由度。这是欧拉角本身的数学缺陷，不是引擎 bug。</li><li><strong>旋转插值不自然</strong>：两个旋转矩阵之间做线性插值，结果通常不是同角速度的旋转——物体会在旋转过程中加速或减速。</li></ul><p>四元数解决了这两个问题：它用一个四维向量表达三维空间中的任意旋转，不存在死锁，而且天然支持球面线性插值（Slerp），保证均匀角速度。</p><h3 id="_2-四元数的几何意义" tabindex="-1">2. 四元数的几何意义 <a class="header-anchor" href="#_2-四元数的几何意义" aria-label="Permalink to &quot;2. 四元数的几何意义&quot;">​</a></h3><p>一个四元数 <code>q = (w, x, y, z)</code> 代表绕单位轴 <code>u = (x, y, z)</code> 旋转角度 <code>θ</code>。其中：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>w = cos(θ/2)</span></span>
<span class="line"><span>x = u.x × sin(θ/2)</span></span>
<span class="line"><span>y = u.y × sin(θ/2)</span></span>
<span class="line"><span>z = u.z × sin(θ/2)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>模长为 1（单位四元数）才代表纯旋转；非单位四元数会引入缩放效果，但在图形学中通常只使用单位四元数。</p><p>一个有用的直觉：四元数和轴角表示在数学上是等价的，但四元数在运算（特别是组合两个旋转）上比轴角方便得多——两个四元数相乘即得到组合旋转。</p><h3 id="_3-四元数运算" tabindex="-1">3. 四元数运算 <a class="header-anchor" href="#_3-四元数运算" aria-label="Permalink to &quot;3. 四元数运算&quot;">​</a></h3><ul><li><strong>乘法</strong>：两个四元数相乘 = 复合旋转（先旋 q1 再旋 q2）。注意四元数乘法不满足交换律——先绕 X 再绕 Y 不等于先绕 Y 再绕 X。</li><li><strong>共轭</strong>：反转旋转方向（逆时针变顺时针）。</li><li><strong>旋转向量</strong>：<code>v&#39; = q · v · q⁻¹</code>（用四元数旋转三维向量）。</li><li><strong>Slerp（球面线性插值）</strong>：在四维超球面上按最短弧插值两个单位四元数，保证旋转过程中角速度恒定。</li></ul><h3 id="_4-引擎中的实用建议" tabindex="-1">4. 引擎中的实用建议 <a class="header-anchor" href="#_4-引擎中的实用建议" aria-label="Permalink to &quot;4. 引擎中的实用建议&quot;">​</a></h3><ul><li>存储用四元数，编辑用欧拉角。Unity Inspector 里显示的是欧拉角，但 <code>Transform.rotation</code> 存的是四元数。原因就是避免 Gimbal Lock 和插值问题。</li><li>自己拼旋转矩阵的时候，可以用 <code>Quaternion.AngleAxis</code> 逐轴指定，比手动推到四元数方便。</li><li>不要直接修改 <code>Quaternion</code> 的 x/y/z/w 分量——你不是在做一个简单的几何旋转，而是在尝试&quot;把四维向量的各分量当做独立自由度调整&quot;，这几乎不会得到你想要的结果。用 <code>Quaternion.Euler</code> 或 <code>AngleAxis</code> 来构造。</li></ul><h2 id="五、投影矩阵" tabindex="-1">五、投影矩阵 <a class="header-anchor" href="#五、投影矩阵" aria-label="Permalink to &quot;五、投影矩阵&quot;">​</a></h2><h3 id="_1-投影的本质" tabindex="-1">1. 投影的本质 <a class="header-anchor" href="#_1-投影的本质" aria-label="Permalink to &quot;1. 投影的本质&quot;">​</a></h3><p>投影矩阵的作用是把三维世界的物体&quot;拍平&quot;到二维屏幕上。它回答了这个问题：&quot;世界空间中用 XYZ 描述的一个点，在屏幕上应该画在哪个像素位置？&quot;</p><p>投影分为正交投影和透视投影两种。</p><h3 id="_2-正交投影" tabindex="-1">2. 正交投影 <a class="header-anchor" href="#_2-正交投影" aria-label="Permalink to &quot;2. 正交投影&quot;">​</a></h3><p>正交投影相当于扔掉一个深度方向，直接从正面看过去。远处的物体和近处的物体一样大，没有&quot;近大远小&quot;。在工程图纸、2D 游戏、UI 布局、以及编辑器视口中的正交模式下常用。</p><p>2D 游戏的摄像机几乎都是正交的。比如《归义军传说》的摄像机就是正交投影，orthographicSize = 5，一个格子在屏幕上固定显示多少像素，不管它在地图上的&quot;前后&quot;位置。</p><h3 id="_3-透视投影" tabindex="-1">3. 透视投影 <a class="header-anchor" href="#_3-透视投影" aria-label="Permalink to &quot;3. 透视投影&quot;">​</a></h3><p>透视投影模拟人眼——远处的物体比近处的小，平行线在远方汇聚于灭点。核心参数是视场角（FOV）和近/远裁剪面。</p><p>透视投影矩阵的非线性特征（z 值越大 → 投影到屏幕上的步长越小）导致一个问题：深度精度不均匀。近处几厘米内的物体有很高的 z-buffer 精度，而远处几十米的区间可能只被分给 100 个离散的深度值。这就是所谓的 <strong>z-fighting</strong> 的根源——远处的两个紧邻物体共享同一个 z-buffer 值，引擎无法判断谁在前面。</p><p>常用缓解方案：尽量拉近裁剪面、推远远裁剪面（但不是万能的——logarithmic z-buffer 和 reversed z-buffer 是更彻底的方案，现代 PC 引擎中已基本普及）。</p><h3 id="_4-透视除法" tabindex="-1">4. 透视除法 <a class="header-anchor" href="#_4-透视除法" aria-label="Permalink to &quot;4. 透视除法&quot;">​</a></h3><p>投影矩阵左乘一个顶点后，顶点进入裁剪空间（Clip Space）。这个矩阵的最后一行的特殊形式使得 w 分量不再是 1，而是携带了深度信息。之后执行<strong>透视除法</strong>——将 x、y、z 分量除以 w——得到归一化设备坐标（NDC，Normalized Device Coordinates），范围 [-1, 1]。</p><p>NDC 中的 x/y 再经过视口变换映射到屏幕像素坐标。整个流水线：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型坐标系 → 世界矩阵 → 观察矩阵 → 投影矩阵 → 裁剪空间 → 透视除法(÷w) → NDC → 视口变换 → 屏幕像素</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="六、总结-什么时候自己写-vs-用引擎的" tabindex="-1">六、总结：什么时候自己写 vs 用引擎的 <a class="header-anchor" href="#六、总结-什么时候自己写-vs-用引擎的" aria-label="Permalink to &quot;六、总结：什么时候自己写 vs 用引擎的&quot;">​</a></h2><ul><li>旋转矩阵的推导：知道就行，不需要手写——引擎都提供 <code>Matrix4x4.Rotate</code> / <code>Quaternion</code>。</li><li>四元数 Slerp：了解原理（为什么球面插值比线性插值好），实际直接用 <code>Quaternion.Slerp</code>。</li><li>投影矩阵：基本不需要自己构造，除非在写自定义的 shadow map 或非标准投影。了解透视除法和 z-fighting 的根源比记住矩阵的 16 个元素有用得多。</li><li><strong>最值得自己动手写一遍的</strong>：MVP 变换链（世界 → 观察 → 投影 → NDC）。写一遍可以彻底搞懂为什么物体的世界坐标最后会变成屏幕上那几个像素——这对调试渲染问题（比如&quot;某个物体明明在摄像机能看到的范围但没渲染出来&quot;）帮助巨大。</li></ul><h2 id="开坑待填" tabindex="-1">开坑待填 <a class="header-anchor" href="#开坑待填" aria-label="Permalink to &quot;开坑待填&quot;">​</a></h2><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><blockquote><p>未完待续</p></blockquote>`,34)])])}const b=e(t,[["render",s]]);export{h as __pageData,b as default};
